export interface Lead {
  id: string;
  name: string;
  category: string;
  address: string;
  phone: string;
  email: string;
  website: string;
  rating: number;
  status: 'New' | 'Contacted' | 'Converted' | 'Invalid';
  source: string;
  latitude?: number;
  longitude?: number;
}

export interface ScrapeParams {
  category: string;
  location: string;
  depth: number;
}

export interface Campaign {
  id: string;
  name: string;
  subject: string;
  content: string;
  status: 'Draft' | 'Sent' | 'Scheduled';
  sentCount: number;
  openRate: number;
  createdAt: Date;
}

export type ViewState = 'dashboard' | 'scraper' | 'leads' | 'campaigns' | 'whatsapp';

import { GoogleGenAI } from "@google/genai";
import { Lead } from "../types";

// Helper to validate API Key
export const hasApiKey = (): boolean => {
  return !!process.env.API_KEY;
};

// Initialize Gemini Client
const getClient = () => {
  if (!process.env.API_KEY) {
    throw new Error("API Key is missing. Please set it in the environment variables.");
  }
  return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

/**
 * Uses Gemini with Google Maps tool to find businesses.
 * Note: Maps tool is strictly for Gemini 2.5 series.
 */
export const searchBusinesses = async (
  category: string,
  location: string
): Promise<Lead[]> => {
  const ai = getClient();

  const prompt = `
    Find 5 distinct "${category}" businesses in "${location}".

    For each business, provide:
    1. Name
    2. Full Address
    3. Phone Number (if available in public listing)
    4. Website URL (if available)
    5. A plausible email address (if not found, generate a likely format like info@domain.com or leave empty)
    6. Rating (simulate a rating between 3.5 and 5.0 if not strictly available)

    Return the data as a pure JSON array of objects. Do not wrap in markdown code blocks. 
    The JSON keys must be: "name", "address", "phone", "email", "website", "rating".

    Example format:
    [
      { "name": "Example Dental", "address": "123 Main St", "phone": "+1 555-0102", "email": "contact@exampledental.com", "website": "https://exampledental.com", "rating": 4.5 }
    ]
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash", // Required for Google Maps tool
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        // We do not set responseMimeType to JSON here because we are using a tool (Maps).
        // Mixing responseSchema/JSON mode with Tools can sometimes be unstable or restricted.
        // We will rely on the prompt to format the text output.
      },
    });

    const text = response.text || "[]";

    // Clean up potential markdown code blocks if the model ignores the "no markdown" instruction
    const cleanedText = text.replace(/```json/g, '').replace(/```/g, '').trim();

    let parsedData: any[] = [];
    try {
      parsedData = JSON.parse(cleanedText);
    } catch (e) {
      console.warn("Failed to parse JSON directly, attempting regex extraction or fallback", e);
      // Fallback: If JSON parse fails, return an empty array or mock data for demo stability
      // In a production app, we would use more robust parsing or Function Calling.
      return [];
    }

    // Map to Lead interface
    const leads: Lead[] = parsedData.map((item: any, index: number) => ({
      id: `lead-${Date.now()}-${index}`,
      name: item.name || "Unknown Business",
      category: category,
      address: item.address || location,
      phone: item.phone || "N/A",
      email: item.email || "",
      website: item.website || "",
      rating: item.rating || 0,
      status: 'New',
      source: 'Google Maps via Gemini',
    }));

    return leads;

  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

/**
 * Generates marketing email content based on a prompt.
 */
export const generateEmailContent = async (
  topic: string,
  tone: string
): Promise<{ subject: string; body: string }> => {
  const ai = getClient();

  const prompt = `
    Write a promotional email for a marketing campaign.
    Topic: ${topic}
    Tone: ${tone}

    Return the response in JSON format with two keys: "subject" and "body".
    The body should be HTML formatted (using <br>, <p>, <strong> tags).
  `;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash", 
    contents: prompt,
    config: {
      responseMimeType: "application/json"
    }
  });

  const text = response.text || "{}";
  return JSON.parse(text);
};

/**
 * Validates a phone number for WhatsApp (Simple heuristic)
 */
export const validateWhatsAppNumber = (phone: string): boolean => {
  // Remove non-digits
  const digits = phone.replace(/\D/g, '');
  // Basic check: length between 10 and 15
  return digits.length >= 10 && digits.length <= 15;
};

import React from 'react';
import { LucideIcon } from 'lucide-react';

interface StatsCardProps {
  title: string;
  value: string | number;
  icon: LucideIcon;
  trend?: string;
  trendUp?: boolean;
  color?: string;
}

export const StatsCard: React.FC<StatsCardProps> = ({ title, value, icon: Icon, trend, trendUp, color = "blue" }) => {
  const colorClasses: Record<string, string> = {
    blue: "bg-blue-100 text-blue-600",
    green: "bg-green-100 text-green-600",
    purple: "bg-purple-100 text-purple-600",
    orange: "bg-orange-100 text-orange-600",
  };

  return (
    <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
      <div className="flex items-center justify-between">
        <div>
          <p className="text-sm font-medium text-gray-500">{title}</p>
          <p className="text-2xl font-bold text-gray-900 mt-1">{value}</p>
        </div>
        <div className={`p-3 rounded-lg ${colorClasses[color] || colorClasses.blue}`}>
          <Icon size={24} />
        </div>
      </div>
      {trend && (
        <div className="mt-4 flex items-center text-sm">
          <span className={trendUp ? "text-green-500 font-medium" : "text-red-500 font-medium"}>
            {trend}
          </span>
          <span className="text-gray-400 ml-2">vs last month</span>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, 
  MapPin, 
  Users, 
  Mail, 
  MessageCircle, 
  Settings, 
  Menu, 
  X,
  Plus,
  Search,
  Download,
  Send,
  Loader2,
  Trash2,
  CheckCircle,
  AlertCircle
} from 'lucide-react';
import { StatsCard } from './components/StatsCard';
import { searchBusinesses, generateEmailContent, hasApiKey, validateWhatsAppNumber } from './services/geminiService';
import { Lead, Campaign, ViewState } from './types';
import { PieChart, Pie, Cell, ResponsiveContainer, Tooltip as RechartsTooltip, BarChart, Bar, XAxis, YAxis, CartesianGrid } from 'recharts';

// --- MOCK DATA FOR DASHBOARD ---
const MOCK_LEADS: Lead[] = [
  { id: '1', name: 'Smile Dental', category: 'Dentist', address: '123 Market St, SF', phone: '+1 415-555-0123', email: 'contact@smiledental.com', website: 'smiledental.com', rating: 4.8, status: 'New', source: 'Manual' },
  { id: '2', name: 'Tech Innovators', category: 'Software', address: '404 Silicon Ave, CA', phone: '+1 650-555-9876', email: 'hello@techinnovators.io', website: 'techinnovators.io', rating: 5.0, status: 'Contacted', source: 'Import' },
  { id: '3', name: 'Green Cafe', category: 'Restaurant', address: '88 Coffee Ln, NY', phone: '+1 212-555-4567', email: 'manager@greencafe.com', website: 'greencafe.com', rating: 4.2, status: 'Converted', source: 'Manual' },
];

const App: React.FC = () => {
  // --- STATE ---
  const [view, setView] = useState<ViewState>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS);

  // Scraper State
  const [scrapeCategory, setScrapeCategory] = useState('');
  const [scrapeLocation, setScrapeLocation] = useState('');
  const [isScraping, setIsScraping] = useState(false);
  const [scrapeError, setScrapeError] = useState<string | null>(null);

  // Campaign State
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [isGeneratingEmail, setIsGeneratingEmail] = useState(false);
  const [emailTopic, setEmailTopic] = useState('');
  const [emailTone, setEmailTone] = useState('Professional');
  const [generatedEmail, setGeneratedEmail] = useState<{subject: string, body: string} | null>(null);

  // Stats
  const totalLeads = leads.length;
  const newLeads = leads.filter(l => l.status === 'New').length;
  const contactedLeads = leads.filter(l => l.status === 'Contacted').length;
  const whatsappReady = leads.filter(l => validateWhatsAppNumber(l.phone)).length;

  // --- ACTIONS ---

  const handleScrape = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasApiKey()) {
      setScrapeError("API Key missing. Please configure process.env.API_KEY.");
      return;
    }

    setIsScraping(true);
    setScrapeError(null);
    try {
      const results = await searchBusinesses(scrapeCategory, scrapeLocation);
      setLeads(prev => [...results, ...prev]); // Add new leads to top
      if (results.length === 0) {
        setScrapeError("No results found. Try a different query or location.");
      } else {
        setView('leads'); // Redirect to leads view to see results
      }
    } catch (err: any) {
      setScrapeError("Failed to scrape. Please try again later. " + err.message);
    } finally {
      setIsScraping(false);
    }
  };

  const handleGenerateEmail = async () => {
    if (!hasApiKey()) return;
    setIsGeneratingEmail(true);
    try {
      const content = await generateEmailContent(emailTopic, emailTone);
      setGeneratedEmail(content);
    } catch (err) {
      console.error(err);
      alert("Failed to generate email content");
    } finally {
      setIsGeneratingEmail(false);
    }
  };

  const saveCampaign = () => {
    if (!generatedEmail) return;
    const newCampaign: Campaign = {
      id: Date.now().toString(),
      name: `Campaign: ${emailTopic.substring(0, 20)}...`,
      subject: generatedEmail.subject,
      content: generatedEmail.body,
      status: 'Draft',
      sentCount: 0,
      openRate: 0,
      createdAt: new Date()
    };
    setCampaigns([newCampaign, ...campaigns]);
    setGeneratedEmail(null);
    setEmailTopic('');
    alert("Campaign saved to drafts!");
  };

  const exportWhatsAppList = () => {
    const validLeads = leads.filter(l => validateWhatsAppNumber(l.phone));
    if (validLeads.length === 0) {
      alert("No valid WhatsApp numbers found.");
      return;
    }

    const csvContent = "data:text/csv;charset=utf-8," 
      + "Name,Phone\n"
      + validLeads.map(l => `${l.name},${l.phone}`).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "whatsapp_leads.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- COMPONENT RENDERERS ---

  const renderDashboard = () => (
