      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
         <StatsCard title="Total Contacts" value={leads.length} icon={Users} color="blue" />
         <StatsCard title="Valid WA Numbers" value={whatsappReady} icon={CheckCircle} color="green" />
         <StatsCard title="Invalid/Landline" value={leads.length - whatsappReady} icon={AlertCircle} color="orange" />
