      <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-lg font-bold text-gray-900">Ready for Export</h3>
          <button 
            onClick={exportWhatsAppList}
            disabled={whatsappReady === 0}
            className={`px-6 py-2 rounded-lg font-medium flex items-center gap-2 transition
              ${whatsappReady > 0 ? 'bg-green-600 text-white hover:bg-green-700 shadow-sm' : 'bg-gray-100 text-gray-400 cursor-not-allowed'}
