import React, { useState } from 'react';
import { X, ChevronRight, MapPin, Search, MessageCircle } from 'lucide-react';

interface OnboardingModalProps {
  onClose: () => void;
}

export const OnboardingModal: React.FC<OnboardingModalProps> = ({ onClose }) => {
  const [step, setStep] = useState(0);

  const steps = [
    {
      title: "Welcome to MapLeads IO",
      description: "Your all-in-one tool to find local business leads, extract contact info, and launch marketing campaigns.",
      icon: <MapPin size={40} className="text-indigo-600" />,
      color: "bg-indigo-100"
    },
    {
      title: "Step 1: Scrape Leads",
      description: "Head to the 'Map Scraper' tab. Enter a business type (e.g. 'Gyms') and location. Use 'Extreme Scan' for the most results.",
      icon: <Search size={40} className="text-blue-600" />,
      color: "bg-blue-100"
    },
    {
      title: "Step 2: Export & Contact",
      description: "Review your leads in the database. You can instantly export valid numbers for WhatsApp or generate AI email campaigns.",
      icon: <MessageCircle size={40} className="text-green-600" />,
      color: "bg-green-100"
    }
  ];

  const handleNext = () => {
    if (step < steps.length - 1) {
      setStep(step + 1);
    } else {
      onClose();
    }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-2xl shadow-2xl max-w-sm w-full relative overflow-hidden animate-in zoom-in-95 duration-300">

        {/* Dismiss Button */}
        <button 
          onClick={onClose}
          className="absolute top-4 right-4 p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-full transition"
        >
          <X size={20} />
        </button>

        {/* Header Image/Icon Area */}
        <div className={`h-32 ${steps[step].color} flex items-center justify-center transition-colors duration-500`}>
          <div className="p-4 bg-white rounded-full shadow-sm transform scale-110 transition-transform">
             {steps[step].icon}
          </div>
        </div>

        {/* Content */}
        <div className="p-8 text-center">
          <h2 className="text-2xl font-bold text-gray-900 mb-3">{steps[step].title}</h2>
          <p className="text-gray-500 mb-8 leading-relaxed text-sm">
            {steps[step].description}
          </p>

          {/* Dots Indicator */}
          <div className="flex justify-center gap-2 mb-6">
            {steps.map((_, i) => (
              <div 
                key={i} 
                className={`h-2 rounded-full transition-all duration-300 ${i === step ? 'w-6 bg-indigo-600' : 'w-2 bg-gray-200'}`} 
              />
            ))}
          </div>

          {/* Action Button */}
          <button 
            onClick={handleNext}
            className="w-full py-3.5 rounded-xl bg-gray-900 text-white font-semibold hover:bg-gray-800 transition-all flex items-center justify-center gap-2 shadow-lg"
          >
            {step === steps.length - 1 ? "Let's Start" : "Next"}
            {step < steps.length - 1 && <ChevronRight size={16} />}
          </button>
        </div>

      </div>
    </div>
  );
};

