export interface WhatsAppCredentials {
  phoneNumberId: string;
  accessToken: string;
}

export const sendWhatsAppMessage = async (
  creds: WhatsAppCredentials,
  to: string,
  body: string
): Promise<{ success: boolean; error?: string }> => {
  if (!creds.phoneNumberId || !creds.accessToken) {
    return { success: false, error: 'Missing credentials' };
  }

  // Format phone: remove non-digits. 
  // The API requires the phone number with country code but without the '+' prefix.
  // Assuming scraped data includes country code (e.g., +1 555...)
  const formattedPhone = to.replace(/\D/g, '');

  const url = `https://graph.facebook.com/v17.0/${creds.phoneNumberId}/messages`;

  try {
    const response = await fetch(url, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${creds.accessToken}`,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({
        messaging_product: 'whatsapp',
        recipient_type: "individual",
        to: formattedPhone,
        type: 'text',
        text: { body: body },
      }),
    });

    const data = await response.json();

    if (!response.ok) {
      return { success: false, error: data.error?.message || 'Unknown API Error' };
    }

    return { success: true };
  } catch (error: any) {
    return { success: false, error: error.message };
  }
};

