  { id: '3', name: 'Green Cafe', category: 'Restaurant', address: '88 Coffee Ln, NY', phone: '+1 212-555-4567', email: 'manager@greencafe.com', website: 'greencafe.com', rating: 4.2, status: 'Converted', source: 'Manual' },
];

type SortKey = 'name' | 'rating' | 'status' | 'address';
type SortDirection = 'asc' | 'desc';

const App: React.FC = () => {
  // --- STATE ---
  const [view, setView] = useState<ViewState>('dashboard');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [leads, setLeads] = useState<Lead[]>(MOCK_LEADS);
  const [selectedLeadIds, setSelectedLeadIds] = useState<Set<string>>(new Set());

  // Onboarding State
  const [showOnboarding, setShowOnboarding] = useState(false);

  // Scraper State
  const [scrapeCategory, setScrapeCategory] = useState('');
  const [scrapeLocation, setScrapeLocation] = useState('');
  const [scrapeMode, setScrapeMode] = useState<'fast' | 'deep' | 'extreme'>('fast');
  const [isScraping, setIsScraping] = useState(false);
  const [scrapeError, setScrapeError] = useState<string | null>(null);

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{key: SortKey, direction: SortDirection}>({ key: 'name', direction: 'asc' });

  // Campaign State
  const [campaigns, setCampaigns] = useState<Campaign[]>([]);
  const [isGeneratingEmail, setIsGeneratingEmail] = useState(false);
  const [emailTopic, setEmailTopic] = useState('');
  const [emailTone, setEmailTone] = useState('Professional');
  const [generatedEmail, setGeneratedEmail] = useState<{subject: string, body: string} | null>(null);

  // WhatsApp State
  const [waCreds, setWaCreds] = useState<WhatsAppCredentials>({ phoneNumberId: '', accessToken: '' });
  const [showWaSettings, setShowWaSettings] = useState(false);
  const [waMessage, setWaMessage] = useState('');
  const [sendingWaMap, setSendingWaMap] = useState<Record<string, boolean>>({}); // Track sending state per lead ID

  // Stats
  const totalLeads = leads.length;
  const newLeads = leads.filter(l => l.status === 'New').length;
  const contactedLeads = leads.filter(l => l.status === 'Contacted').length;
  const whatsappReady = leads.filter(l => validateWhatsAppNumber(l.phone)).length;

  // --- EFFECTS ---
  useEffect(() => {
    const hasSeenOnboarding = localStorage.getItem('mapleads_onboarding_seen');
    if (!hasSeenOnboarding) {
      setShowOnboarding(true);
    }

    // Load WhatsApp Creds
    const storedWaPhoneId = localStorage.getItem('mapleads_wa_phone_id');
    const storedWaToken = localStorage.getItem('mapleads_wa_token');
    if (storedWaPhoneId && storedWaToken) {
      setWaCreds({ phoneNumberId: storedWaPhoneId, accessToken: storedWaToken });
    }
  }, []);

  const handleCloseOnboarding = () => {
    localStorage.setItem('mapleads_onboarding_seen', 'true');
    setShowOnboarding(false);
  };

  // --- ACTIONS ---

  const handleScrape = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!hasApiKey()) {
      setScrapeError("API Key missing. Please configure process.env.API_KEY.");
      return;
    }

    setIsScraping(true);
    setScrapeError(null);
    try {
      const results = await searchBusinesses(scrapeCategory, scrapeLocation, scrapeMode);
      setLeads(prev => [...results, ...prev]); // Add new leads to top
      if (results.length === 0) {
        setScrapeError("No results found. Try a different query or location.");
      } else {
        setView('leads'); // Redirect to leads view to see results
      }
    } catch (err: any) {
      setScrapeError("Failed to scrape. Please try again later. " + err.message);
    } finally {
      setIsScraping(false);
    }
  };

  const handleGenerateEmail = async () => {
    if (!hasApiKey()) return;
    setIsGeneratingEmail(true);
    try {
      const content = await generateEmailContent(emailTopic, emailTone);
      setGeneratedEmail(content);
    } catch (err) {
      console.error(err);
      alert("Failed to generate email content");
    } finally {
      setIsGeneratingEmail(false);
    }
  };

  const saveCampaign = () => {
    if (!generatedEmail) return;
    const newCampaign: Campaign = {
      id: Date.now().toString(),
      name: `Campaign: ${emailTopic.substring(0, 20)}...`,
      subject: generatedEmail.subject,
      content: generatedEmail.body,
      status: 'Draft',
      sentCount: 0,
      openRate: 0,
      createdAt: new Date()
    };
    setCampaigns([newCampaign, ...campaigns]);
    setGeneratedEmail(null);
    setEmailTopic('');
    alert("Campaign saved to drafts!");
  };

  // --- WHATSAPP ACTIONS ---

  const saveWaCredentials = () => {
    localStorage.setItem('mapleads_wa_phone_id', waCreds.phoneNumberId);
    localStorage.setItem('mapleads_wa_token', waCreds.accessToken);
    setShowWaSettings(false);
    alert("WhatsApp credentials saved!");
  };

  const handleSendWhatsApp = async (lead: Lead) => {
    if (!waCreds.phoneNumberId || !waCreds.accessToken) {
      alert("Please configure WhatsApp Credentials first.");
      setShowWaSettings(true);
      return;
    }
    if (!waMessage.trim()) {
      alert("Please enter a message.");
      return;
    }

    setSendingWaMap(prev => ({ ...prev, [lead.id]: true }));

    const result = await sendWhatsAppMessage(waCreds, lead.phone, waMessage);

    setSendingWaMap(prev => {
      const newState = { ...prev };
      delete newState[lead.id];
      return newState;
    });

    if (result.success) {
      // Mark as contacted
      setLeads(prev => prev.map(l => l.id === lead.id ? { ...l, status: 'Contacted' } : l));
      alert(`Message sent to ${lead.name}!`);
    } else {
      alert(`Failed to send to ${lead.name}: ${result.error}`);
    }
  };

  const handleBulkSendWhatsApp = async () => {
     if (!waCreds.phoneNumberId || !waCreds.accessToken) {
      alert("Please configure WhatsApp Credentials first.");
      setShowWaSettings(true);
      return;
    }

    const validLeads = leads.filter(l => validateWhatsAppNumber(l.phone));
    if (validLeads.length === 0) return alert("No valid numbers found.");

    if(!window.confirm(`Send message to ${validLeads.length} leads? This may take some time.`)) return;

    // Process sequentially to be nice to the API (simple rate limiting)
    let successCount = 0;
    let failCount = 0;

    for (const lead of validLeads) {
      setSendingWaMap(prev => ({ ...prev, [lead.id]: true }));
      const result = await sendWhatsAppMessage(waCreds, lead.phone, waMessage);
      setSendingWaMap(prev => {
        const newState = { ...prev };
        delete newState[lead.id];
        return newState;
      });

      if (result.success) {
        successCount++;
        setLeads(prev => prev.map(l => l.id === lead.id ? { ...l, status: 'Contacted' } : l));
      } else {
        failCount++;
      }
      // Small delay
      await new Promise(r => setTimeout(r, 500));
    }

    alert(`Bulk Send Complete.\nSuccess: ${successCount}\nFailed: ${failCount}`);
  };

  const exportWhatsAppList = () => {
    const validLeads = leads.filter(l => validateWhatsAppNumber(l.phone));
    if (validLeads.length === 0) {
      alert("No valid WhatsApp numbers found.");
      return;
    }

    const csvContent = "data:text/csv;charset=utf-8," 
      + "Name,Phone\n"
      + validLeads.map(l => `${l.name},${l.phone}`).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "whatsapp_leads.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- BULK ACTIONS ---

  const toggleSelectAll = () => {
    if (selectedLeadIds.size === leads.length && leads.length > 0) {
      setSelectedLeadIds(new Set());
    } else {
      setSelectedLeadIds(new Set(leads.map(l => l.id)));
    }
  };

  const toggleSelectLead = (id: string) => {
    const newSet = new Set(selectedLeadIds);
    if (newSet.has(id)) {
      newSet.delete(id);
    } else {
      newSet.add(id);
    }
    setSelectedLeadIds(newSet);
  };

  const handleBulkDelete = () => {
    if (window.confirm(`Are you sure you want to delete ${selectedLeadIds.size} leads?`)) {
      setLeads(prev => prev.filter(l => !selectedLeadIds.has(l.id)));
      setSelectedLeadIds(new Set());
    }
  };

  const handleBulkStatusChange = (status: Lead['status']) => {
    setLeads(prev => prev.map(l => selectedLeadIds.has(l.id) ? { ...l, status } : l));
    setSelectedLeadIds(new Set());
  };

  const handleBulkExport = () => {
    const selectedLeads = leads.filter(l => selectedLeadIds.has(l.id));
    if (selectedLeads.length === 0) return;

    const csvContent = "data:text/csv;charset=utf-8," 
      + "Name,Category,Phone,Email,Address,Status,Rating\n"
      + selectedLeads.map(l => `"${l.name}","${l.category}","${l.phone}","${l.email}","${l.address}","${l.status}","${l.rating}"`).join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "selected_leads.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  // --- SORTING ---
  const handleSort = (key: SortKey) => {
    setSortConfig(current => ({
      key,
      direction: current.key === key && current.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  const sortedLeads = [...leads].sort((a, b) => {
    const aValue = a[sortConfig.key];
    const bValue = b[sortConfig.key];

    if (typeof aValue === 'string' && typeof bValue === 'string') {
      return sortConfig.direction === 'asc' 
        ? aValue.localeCompare(bValue) 
        : bValue.localeCompare(aValue);
    }
    if (typeof aValue === 'number' && typeof bValue === 'number') {
      return sortConfig.direction === 'asc' ? aValue - bValue : bValue - aValue;
    }
    return 0;
  });

