      ? <ArrowUp size={14} className="ml-1 text-indigo-600" />
      : <ArrowDown size={14} className="ml-1 text-indigo-600" />;
  };


  // --- COMPONENT RENDERERS ---

  const renderDashboard = () => (
    <div className="space-y-6 animate-fade-in">
