  name: string;
  category: string;
  address: string;
  phone: string;
  email: string;
  website: string;
  rating: number;
  status: 'New' | 'Contacted' | 'Converted' | 'Invalid' | 'Skipped';
  source: string;
  latitude?: number;
  longitude?: number;
}

