                     onChange={handleImageSelect}
                   />

                   {!waImage ? (
                     <button 
                       onClick={() => fileInputRef.current?.click()}
                       className="text-sm font-medium text-gray-500 hover:text-green-600 flex items-center gap-2 transition"
