                <button 
                  onClick={handleBulkOpenWhatsApp}
                  className="w-full py-4 bg-green-500 hover:bg-green-600 text-white font-bold rounded-xl shadow-lg hover:shadow-xl transition flex items-center justify-center gap-3"
                >
