                </button>

                <div className="flex gap-3">
                   <button 
                     onClick={() => handleBulkNext('Contacted')}
                     className="flex-1 py-3 bg-indigo-50 text-indigo-700 hover:bg-indigo-100 font-bold rounded-xl transition flex items-center justify-center gap-2"
                   >
                     <Check size={20} /> 2. Mark Sent & Next
                   </button>
                   <button 
                     onClick={() => handleBulkNext('Skipped')}
                     className="flex-1 py-3 border border-red-200 text-red-600 bg-red-50 hover:bg-red-100 font-medium rounded-xl transition flex items-center justify-center gap-2"
                     title="Skip this contact and mark as not sent"
                   >
                     <XSquare size={20} /> Mark Not Sent
                   </button>
                </div>
             </div>

             <p className="mt-6 text-xs text-gray-400 max-w-xs mx-auto leading-relaxed">
               {waImage 
                 ? (canUseNativeShare 
                    ? "Click Open. Your phone will ask where to share the image. Select WhatsApp."
