                   >
                     <Check size={18} /> 2. Next
                   </button>
                   <button 
                     onClick={() => handleBulkNext('Skipped')}
                     className="px-4 py-3 border-2 border-gray-100 text-gray-400 hover:text-red-500 hover:border-red-100 hover:bg-red-50 font-medium rounded-xl transition flex items-center justify-center active:scale-[0.98]"
                     title="Skip this contact"
                   >
                     <XSquare size={20} />
                   </button>
                </div>
             </div>

             <p className="mt-8 text-xs text-gray-400 max-w-xs mx-auto">
                Step 1 opens the chat. Step 2 marks it as done and loads the next person.
             </p>
          </div>

        </div>
      </div>
    );
  };

  const renderCacheExpiryModal = () => {
    if (!showCacheExpiryModal) return null;

    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md p-6 text-center animate-in zoom-in-95 border border-gray-100">
              <div className="w-16 h-16 bg-amber-100 rounded-full flex items-center justify-center mx-auto mb-4 text-amber-600">
                  <History size={32} />
              </div>
              <h3 className="text-xl font-bold text-gray-900 mb-2">Weekly Data Cleanup</h3>
              <p className="text-gray-500 mb-6 text-sm">
                  It's been 7 days since your last cleanup. To keep the app fast, we recommend clearing old data. 
                  <br/><br/>
                  <strong className="text-gray-700">Do you want to keep your current leads and history?</strong>
              </p>

              <div className="flex flex-col gap-3">
                  <button 
                      onClick={handleKeepData}
                      className="w-full py-3 bg-indigo-600 text-white font-bold rounded-xl hover:bg-indigo-700 transition flex items-center justify-center gap-2"
                  >
                      <CheckCircle size={20} /> Keep Data (Extend 7 Days)
                  </button>
                  <button 
                      onClick={handleClearData}
                      className="w-full py-3 bg-white border-2 border-gray-200 text-gray-600 font-bold rounded-xl hover:bg-gray-50 hover:text-red-600 hover:border-red-100 transition flex items-center justify-center gap-2"
                  >
                      <Trash2 size={20} /> Clear Data & Start Fresh
                  </button>
              </div>
          </div>
      </div>
    );
  }

  // --- NAVIGATION HELPER ---
  const getNextStep = () => {
    switch (view) {
      case 'dashboard': return { id: 'scraper', label: 'Find Leads', icon: Search };
      case 'scraper': return { id: 'leads', label: 'View Leads', icon: Users };
      case 'leads': return { id: 'campaigns', label: 'Create Campaign', icon: Sparkles };
      case 'campaigns': return { id: 'whatsapp', label: 'Send Messages', icon: MessageCircle };
      case 'whatsapp': return { id: 'dashboard', label: 'Back Home', icon: LayoutDashboard };
      default: return null;
    }
  };

  const nextStep = getNextStep();

  const handleNextStep = () => {
    if (nextStep) {
      setView(nextStep.id as ViewState);
      // Close sidebar on mobile if navigating
      setIsSidebarOpen(false);
      // Scroll to top
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // --- MAIN RENDER ---
  return (
    <div className="flex min-h-screen bg-gray-50 relative">

      {/* Watermark - Moved to Left */}
      <div className="fixed bottom-2 left-2 z-40 pointer-events-none opacity-40 hover:opacity-100 transition-opacity select-none hidden lg:block">
        <span className="text-[10px] font-medium text-slate-500 bg-white/50 backdrop-blur-[2px] px-2 py-1 rounded-md border border-slate-100/50">
          Made with ❤️ by Sardar Toheed
        </span>
      </div>

      {/* Floating Next Step Button */}
      {nextStep && (
        <div className="fixed bottom-6 right-6 z-40 animate-in slide-in-from-bottom-10 fade-in duration-500">
          <button
            onClick={handleNextStep}
            className="bg-gray-900 hover:bg-indigo-600 text-white pl-5 pr-4 py-3 rounded-full shadow-xl hover:shadow-2xl hover:-translate-y-1 transition-all duration-300 flex items-center gap-3 font-medium text-sm border border-white/10 group backdrop-blur-sm"
          >
            <span>{nextStep.label}</span>
            <div className="bg-white/20 p-1.5 rounded-full group-hover:bg-white/30 transition-colors">
               <ArrowRight size={16} />
            </div>
          </button>
        </div>
      )}

      {/* Modals */}
      {showOnboarding && <OnboardingModal onClose={handleCloseOnboarding} />}
      {showCacheExpiryModal && renderCacheExpiryModal()}
      {renderBulkSessionModal()}

      {/* Mobile Sidebar Overlay */}
      {isSidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/20 z-20 lg:hidden backdrop-blur-sm"
          onClick={() => setIsSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`
        fixed lg:static inset-y-0 left-0 z-30 w-64 bg-white border-r border-gray-200 transform transition-transform duration-200 ease-in-out
        ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        <div className="h-full flex flex-col">
          <div className="p-6 flex items-center gap-3">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold text-lg">
              M
            </div>
            <span className="text-xl font-bold text-gray-900 tracking-tight">MapLeads IO</span>
          </div>

          <nav className="flex-1 px-4 space-y-1 mt-4">
            <NavItem icon={LayoutDashboard} label="Dashboard" active={view === 'dashboard'} onClick={() => { setView('dashboard'); setIsSidebarOpen(false); }} />
            <NavItem icon={Search} label="Map Scraper" active={view === 'scraper'} onClick={() => { setView('scraper'); setIsSidebarOpen(false); }} />
            <NavItem icon={Users} label="Leads" active={view === 'leads'} onClick={() => { setView('leads'); setIsSidebarOpen(false); }} />
            <NavItem icon={Mail} label="Generate Campaigns" active={view === 'campaigns'} onClick={() => { setView('campaigns'); setIsSidebarOpen(false); }} />
            <NavItem icon={MessageCircle} label="WhatsApp Tools" active={view === 'whatsapp'} onClick={() => { setView('whatsapp'); setIsSidebarOpen(false); }} />
          </nav>

          <div className="p-4 border-t border-gray-100">
             <div className="bg-indigo-50 rounded-xl p-4">
               <div className="flex items-center gap-3 mb-2">
                 <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></div>
                 <span className="text-xs font-semibold text-indigo-900">System Online</span>
               </div>
               <p className="text-xs text-indigo-700/70">
                 Gemini 2.5 Active
               </p>
             </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Header */}
        <header className="h-16 bg-white border-b border-gray-200 flex items-center justify-between px-6 flex-shrink-0">
          <button 
            onClick={() => setIsSidebarOpen(true)}
            className="lg:hidden p-2 -ml-2 text-gray-600 hover:bg-gray-100 rounded-lg"
          >
            <Menu size={20} />
          </button>

          <div className="ml-auto flex items-center gap-4">
             <div className="hidden sm:flex items-center text-sm text-gray-500 bg-gray-100 px-3 py-1.5 rounded-full">
               <span className="mr-2">Credit Balance:</span>
               <span className="font-bold text-gray-900">Unlimited</span>
             </div>
             <div className="w-8 h-8 rounded-full bg-gradient-to-tr from-indigo-500 to-purple-500 text-white flex items-center justify-center font-bold text-xs cursor-pointer shadow-md shadow-indigo-200">
               JS
             </div>
          </div>
        </header>

        {/* Scrollable Content Area */}
        <div className="flex-1 overflow-y-auto p-6 lg:p-10">
          <div className="max-w-7xl mx-auto">
             <div className="mb-8">
               <h1 className="text-2xl font-bold text-gray-900 capitalize">
                 {view === 'scraper' ? 'Lead Scraper' : view === 'campaigns' ? 'Generate Campaigns' : view.replace('-', ' ')}
               </h1>
               <p className="text-gray-500 text-sm mt-1">
                 {view === 'dashboard' && 'Overview of your marketing performance'}
                 {view === 'scraper' && 'Extract data from Google Maps in seconds'}
                 {view === 'leads' && 'Manage and organize your gathered contacts'}
                 {view === 'campaigns' && 'Create content for emails or WhatsApp messages using AI'}
                 {view === 'whatsapp' && 'Prepare lists for mobile marketing'}
               </p>
             </div>

             {view === 'dashboard' && renderDashboard()}
             {view === 'scraper' && renderScraper()}
             {view === 'leads' && renderLeads()}
             {view === 'campaigns' && renderCampaigns()}
             {view === 'whatsapp' && renderWhatsApp()}
          </div>
        </div>
      </main>
    </div>
  );
};

// Helper Component for Navigation
