                          <Locate size={20} />
                        </button>
                        <button 
                          type="button" 
                          onClick={handleLookupLocation}
                          className="p-3 text-gray-500 hover:text-primary hover:bg-primaryContainer rounded-full transition"
                          title="Verify Location"
                        >
                          <Search size={20} />
                        </button>
                     </>
                   )}
                </div>
              </div>
            </div>
          </div>

          <div className="space-y-2">
