    const csvContent = "data:text/csv;charset=utf-8," 
      + "Name,Category,Phone,Email,Address,Status,Rating\n"
      + selectedLeads.map(l => `"${l.name}","${l.category}","${l.phone}","${l.email}","${l.address}","${l.status}","${l.rating}"`).join("\n");

