        <div className="bg-white rounded-xl p-6 shadow-card h-fit border border-transparent">
          <h3 className="text-lg font-normal text-textMain mb-4">Lead Status</h3>
          <div className="h-64">
             <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
