  const handleWhatsAppAction = (lead: Lead) => {
    if (!validateWhatsAppNumber(lead.phone)) {
      addToast("Invalid phone number for WhatsApp", 'warning');
      return;
    }

    // Basic template
    const text = `Hello ${lead.name}, I found your business on Google Maps and would like to inquire about your services.`;
